FUNCTION CalculateNetworkAddress(ipAddress, subnetMask)
 // Convert IP and subnet to binary
 ipBinary = ConvertToBinary(ipAddress)
 maskBinary = ConvertToBinary(subnetMask)

 // Perform bitwise AND operation
 networkBinary = ipBinary AND maskBinary

 // Convert back to decimal
 networkAddress = ConvertToDecimal(networkBinary)

 RETURN networkAddress
END FUNCTION
